example.code:
@dataclass
class OrderBuilder:
    _status: str = "pending"
    _items: List[OrderItem] = field(default_factory=list)
    _discount: Optional[Decimal] = None

    def with_item(self, sku: str, price: Decimal, qty: int = 1) -> "OrderBuilder":
        self._items.append(OrderItem(sku=sku, price=price, quantity=qty))
        return self

    def with_discount(self, amount: Decimal) -> "OrderBuilder":
        self._discount = amount
        return self

    def build(self) -> Order:
        return Order(items=self._items, status=self._status, discount=self._discount)

# Usage — reads like a spec
order = (OrderBuilder()
    .with_item(sku="A", price=Decimal("15.00"), qty=2)
    .with_discount(Decimal("5.00"))
    .build())
